mapper.select:
SELECT o.id, o.shopid, s.name AS shop_name, o.ftype, o.out_trade_no, o.subject, o.trade_no, o.total_amount, o.discountnumber, o.paytime, o.paystatus, o.ivcstatus, o.months, o.tariffpackage, p.name AS package_name, o.pcs, o.paytype, o.disable, CASE WHEN i.orderid IS NOT NULL THEN 1 ELSE 0 END AS has_invoice_request, f.location FROM t_sys_customer_order o LEFT JOIN t_shop s ON o.shopid = s.id LEFT JOIN t_sys_tariff_packages p ON o.tariffpackage = p.id LEFT JOIN t_sys_customer_invoice i ON o.id = i.orderid left join t_sys_tool_large_file f on f.id=i.invoice_file WHERE 1=1 AND o.disable = FALSE and o.shopid=#{query.shopid}
AND ( o.out_trade_no LIKE CONCAT('%', #{query.search}, '%') OR o.subject LIKE CONCAT('%', #{query.search}, '%') OR o.trade_no LIKE CONCAT('%', #{query.search}, '%') OR s.name LIKE CONCAT('%', #{query.search}, '%') OR p.name LIKE CONCAT('%', #{query.search}, '%') )
AND o.ftype = #{query.ftype}
AND o.paystatus = #{query.paystatus}
AND o.ivcstatus = #{query.ivcstatus}
AND o.paytime >= #{query.startTime}
AND o.paytime <= #{query.endTime}
AND o.shopid = #{query.shopid}
AND o.tariffpackage = #{query.tariffpackage}
AND i.orderid IS NOT NULL
ORDER BY o.paytime DESC

